import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './StandaloneAdminDashboard.css';

const StandaloneAdminDashboard = () => {
  const [admin, setAdmin] = useState(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const navigate = useNavigate();

  useEffect(() => {
    // Check if admin is logged in
    const adminSession = JSON.parse(sessionStorage.getItem('adminSession'));
    
    if (!adminSession || !adminSession.isAdmin) {
      navigate('/standalone-admin');
      return;
    }
    
    setAdmin(adminSession);
  }, [navigate]);

  const handleLogout = () => {
    sessionStorage.removeItem('adminSession');
    navigate('/standalone-admin');
  };

  if (!admin) {
    return (
      <div className="admin-loading">
        <div className="spinner"></div>
        <p>Checking admin access...</p>
      </div>
    );
  }

  return (
    <div className="standalone-admin-dashboard">
      {/* Header */}
      <div className="admin-header">
        <div className="admin-header-content">
          <h1>👨‍💼 Standalone Admin Dashboard</h1>
          <div className="admin-actions">
            <span>Welcome, {admin.name}</span>
            <button onClick={handleLogout} className="btn-logout">
              🚪 Logout
            </button>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <div className="admin-nav">
        <button 
          className={`nav-btn ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button 
          className={`nav-btn ${activeTab === 'users' ? 'active' : ''}`}
          onClick={() => setActiveTab('users')}
        >
          👥 User Management
        </button>
        <button 
          className={`nav-btn ${activeTab === 'requests' ? 'active' : ''}`}
          onClick={() => setActiveTab('requests')}
        >
          📨 Mentorship Requests
        </button>
        <button 
          className={`nav-btn ${activeTab === 'settings' ? 'active' : ''}`}
          onClick={() => setActiveTab('settings')}
        >
          ⚙️ System Settings
        </button>
      </div>

      {/* Dashboard Content */}
      <div className="admin-content">
        {activeTab === 'dashboard' && (
          <div className="dashboard-tab">
            <h2>Admin Dashboard Overview</h2>
            <div className="stats-grid">
              <div className="stat-card">
                <h3>Total Users</h3>
                <span className="stat-number">1,247</span>
                <p>Registered users</p>
              </div>
              <div className="stat-card">
                <h3>Active Mentors</h3>
                <span className="stat-number">89</span>
                <p>Available mentors</p>
              </div>
              <div className="stat-card">
                <h3>Pending Requests</h3>
                <span className="stat-number">23</span>
                <p>Mentorship requests</p>
              </div>
              <div className="stat-card">
                <h3>System Health</h3>
                <span className="stat-number">100%</span>
                <p>All systems operational</p>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'users' && (
          <div className="users-tab">
            <h2>User Management</h2>
            <p>User management functionality would go here.</p>
          </div>
        )}

        {activeTab === 'requests' && (
          <div className="requests-tab">
            <h2>Mentorship Requests</h2>
            <p>Mentorship request management would go here.</p>
          </div>
        )}

        {activeTab === 'settings' && (
          <div className="settings-tab">
            <h2>System Settings</h2>
            <p>System configuration would go here.</p>
          </div>
        )}
      </div>

      <div className="admin-footer">
        <p>🔒 Standalone Admin System - Completely independent from user authentication</p>
      </div>
    </div>
  );
};

export default StandaloneAdminDashboard;
